import React, { useState } from 'react';
import { NavLink } from 'react-router-dom';
import classNames from 'classnames';
import './Header.scss';

export const Header = () => {
  const [menu, setMenu] = useState('false');
  const [query, setQuery] = useState('');
  // const history = useHistory();
  // const val = history.location.pathname;
  // console.log(history.location.pathname);

  const menuItems = [
    'Plan you vaccine', 'Covid-19', 'Politics',
    'U.S.News', 'Opinion', 'World', 'Busness', 'Tech',
  ];

  return (
    <header className="Header">
      <div className={classNames('container', {
        container_menu: menu,
        })}
      >
        <a href="articles" className="Header-Logo">NEWS</a>
        <div className="Header-Menu Menu">
          <ul className={classNames('Menu-List', {
            menu_visible: menu,
          })}
          >
            {menuItems.map(item => (
              <li className="Menu-Item" key={item}>
                <NavLink
                  to={item}
                  className="Menu-Link"
                >
                  {item.toUpperCase()}
                </NavLink>
              </li>
            ))}
          </ul>
          <button
            type="button"
            className={classNames('button-menu', {
              menu_open: !menu,
              menu_cross: menu,
            })}
            onClick={() => setMenu(!menu)}
          />
        </div>
      </div>
      <div className={classNames('container-header', {
        container_tablet: !menu,
      })}
      >
        <h2 className="Header-LogoPage">News App</h2>
        <div className={classNames('container-nav', {
        })}
        >
          <form className="Header-Form form">
            <button
              type="button"
              className="button-search"
              onClick={() => setQuery('')}
            />
            <input
              type="text"
              className="form-input"
              value={query}
              onChange={e => setQuery(e.target.value)}
              placeholder="Search..."
            />
            {query && (
              <button
                type="button"
                className="button-clear"
                onClick={() => setQuery('')}
              >
                X
              </button>
            )}
          </form>
          <nav className="Header-Nav Nav">
            <NavLink to="home" className="Nav-Link">Home</NavLink>
            <NavLink to="articles" className="Nav-Link">Articles</NavLink>
          </nav>
          <a href="http://insagram.com" className="Header-Instagram link">{}</a>
          <a href="http://twitter.com" className="Header-Twitter link">{}</a>
          <a href="http://linkedin.com" className="Header-LinkedIn link">{}</a>
        </div>
      </div>
    </header>
  );
};
